# 生成特殊城市图
city_map = {}
for i in range(1, 2024):
    for j in range(i+1, 2024):
        if abs(j - i) > 23:
            continue
        lcm = abs(i*j) // math.gcd(i, j)
        city_map[(i, j)] = lcm
        city_map[(j, i)] = lcm


# 蚁群算法
class ACO:
    def init(self, ant_count=50, alpha=1, beta=2, evaporation_rate=0.5,
                 q=100, generations=100):
        self.ant_count = ant_count
        self.alpha = alpha
        self.beta = beta
        self.evaporation_rate = evaporation_rate
        self.q = q
        self.generations = generations
        self.best_path = None
        self.best_cost = float('inf')
        self.pheromone_map = None

    def create_route(self):
        route = [1]
        while len(route) < 2023:
            next_city = None
            max_prob = 0
            total_prob = 0
            for i in range(2, 2024):
                if i in route or abs(route[-1] - i) > 23:
                    continue
                prob = self.pheromone_map[route[-1]-1, i-1] ** self.alpha <br/>                       * (1 / city_map[(route[-1], i)]) ** self.beta
                total_prob += prob
                if prob > max_prob:
                    max_prob = prob
                    next_city = i
            if next_city:
                route.append(next_city)
        return route + [1]

    def initial_pheromone_map(self):
        self.pheromone_map = [[1.0] * 2023 for _ in range(2023)]

    def update_pheromone_map(self, routes):
        for i in range(2023):
            for j in range(2023):
                if i == j:
                    continue
                delta_pheromone = 0
                for route in routes:
                    if j + 1 in route and i + 1 in route[route.index(j + 1):]:
