Tampermonkey:
// ==UserScript==
// @name         Discord Message Logger
// @namespace    http://tampermonkey.net/
// @version      1.0
// @description  Sends the latest message in a Discord server to a Node.js server whenever a new message is received.
// @author       Your Name
// @match        https://discord.com/*
// @grant        none
// ==/UserScript==

(function() {
  'use strict';

  let lastMessage = {
    author: '',
    content: ''
  };

  // Function to send the latest message to the server
  function sendLatestMessage(message) {
    const url = 'http://127.0.0.1:8080/endpoint';  // Use the server URL and endpoint

    fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(message),
    })
    .then(response => {
      if (response.ok) {
        console.log('Message sent successfully');
      } else {
        console.log('Failed to send message');
      }
    })
    .catch(error => {
      console.log('Error occurred while sending message:', error);
    });
  }

  // Function to log the latest message
  function logLatestMessage() {
    const messageContainer = document.querySelector('[class^="messagesWrapper-"]');
    if (!messageContainer) {
      console.log('Message container not found');
      return;
    }

    const messages = messageContainer.querySelectorAll('[class^="message-"]');
    if (!messages.length) {
      console.log('No messages found');
      return;
    }

    const latestMessage = messages[messages.length - 1];
    const authorElement = latestMessage.querySelector('[class^="username-"]');
    if (!authorElement) {
      console.log('Author element not found');
      return;
    }
    const author = authorElement.textContent;

    // Look for message content in different possible class names
    const contentElement = latestMessage.querySelector('[class^="markup-"], [class^="messageContent-"], [class^="messageContentEdited-"]');
    const content = contentElement ? contentElement.textContent : '';

    const latestMessageData = {
      author,
      content
    };

    if (latestMessageData.author !== lastMessage.author || latestMessageData.content !== lastMessage.content) {
      lastMessage = latestMessageData;
      sendLatestMessage(lastMessage);
    }
  }

  // Listen for new message events
  document.addEventListener('DOMNodeInserted', logLatestMessage);
})();

