            [canvas.width, canvas.height - 50],
            [canvas.width, canvas.height],
            [0, canvas.height]
        ])));
        this.platforms.push(new Platform(new Polygon([
            [0, canvas.height - 200],
            [500, canvas.height - 200],
            [500, canvas.height - 150],
            [0, canvas.height - 150]
        ])));
        this.platforms.push(new Platform(new Polygon([
            [0, canvas.height - 300],
            [500, canvas.height - 300],
            [500, canvas.height - 250],
            [0, canvas.height - 250]
        ])));
        this.keys = {};
        document.addEventListener("keydown", evt => {
            this.keys[evt.keyCode] = true;
        });
        document.addEventListener("keyup", evt => {
            delete this.keys[evt.keyCode];
        });
        requestAnimationFrame(this.update.bind(this));
    }

    update() {
        this.player.move(this.keys);
        for (let i = 0; i < this.platforms.length; i++) {
            if (this.platforms[i].collidesWith(this.player.geometry)) {
                let normal = /* Calculate normal vector based on collision */;
                this.platforms[i].resolveCollision(this.player.geometry, normal);
            }
        }
        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
        for (let i = 0; i < this.platforms.length; i++) {
            let p = this.platforms[i].geometry.vertices;
            this.ctx.fillStyle = "black";
            this.ctx.beginPath();
            this.ctx.moveTo(p[0][0], p[0][1]);
            for (let j = 1; j < p.length; j++) {
                this.ctx.lineTo(p[j][0], p[j][1]);
            }
            this.ctx.closePath();
            this.ctx.fill();
        }
        let pPlayer = this.player.geometry.vertices;
        this.ctx.fillStyle = "red";
        this.ctx.beginPath();
        this.ctx.moveTo(pPlayer[0][0], pPlayer[0][1]);
        for (let j = 1; j < pPlayer.length; j++) {
            this.ctx.lineTo(pPlayer[j][0], pPlayer[j][1]);
        }
        this.ctx.closePath();
        this.ctx.fill();
        requestAnimationFrame(this.update.bind(this));
    }
