also, there’s a problem with this exponential slowdown. because it endlessly slowdowns, until it reaches a year in timeout, which is idiotic. maybe if request is passed then reset slowdown exponent? how? implement?: async function query(data, modelToken) {
  const url = modelUrl;

  const response = await fetch(url, {
    headers: {
      "Content-Type": "application/json",
      Authorization: "Bearer " + modelToken
    },
    method: 'POST',
    body: data
  });

  const headers = response.headers;
  const estimatedTimeString = headers.get('estimated_time');
  estimatedTime = parseFloat(estimatedTimeString) * 1000;

  // Handle HTTP 429 errors by throwing an error with the response object
  if (response.status === 429) {
    const error = new Error('Backend error');
    error.response = response;
    throw error;
  }

  const result = await response.blob();
