کتاب خانه cuda را به برنامه زیر اضافه کن و آن را بهینه کن :
#include <iostream>
#include <cstdlib>
#include <ctime>

void multiply_matrices(int n) {
// ایجاد دو ماتریس n*n با مقادیر تصادفی
int matrix1[n][n];
int matrix2[n][n];
int result[n][n];

// مقداردهی تصادفی به ماتریس‌ها
srand(time(0));
for (int i = 0; i < n; i++) {
for (int j = 0; j < n; j++) {
matrix1[i][j] = rand() % 10;
matrix2[i][j] = rand() % 10;
}
}

// ضرب دو ماتریس
for (int i = 0; i < n; i++) {
for (int j = 0; j < n; j++) {
result[i][j] = 0;
for (int k = 0; k < n; k++) {
result[i][j] += matrix1[i][k] * matrix2[k][j];
}
}
}

// نمایش نتیجه ضرب دو ماتریس
std::cout << "نتیجه ضرب دو ماتریس:" << std::endl;
for (int i = 0; i < n; i++) {
for (int j = 0; j < n; j++) {
std::cout << result[i][j] << " ";
}
std::cout << std::endl;
}
}

int main() {
int n;
std::cout << "تعداد سطر و ستون ماتریس را وارد کنید: ";
std::cin >> n;

// فراخوانی تابع ضرب ماتریس
multiply_matrices(n);

return 0;
}

