function line(x1, y1, z1, x2, y2, z2, id) {
	let dx = Math.abs(x2 - x1);
	let dy = Math.abs(y2 - y1);
	let dz = Math.abs(z2 - z1);
	let sx = (x1 < x2) ? 1 : -1;
	let sy = (y1 < y2) ? 1 : -1;
	let sz = (z1 < z2) ? 1 : -1;
	let err1 = dx - dy;
	let err2 = dx - dz;
	let err3 = dy - dz;

	while (true) {
		world.setBlock(x1, y1, z1, id);

		if (x1 === x2 && y1 === y2 && z1 === z2) break;
		let e2 = 2 * err1;
		let e3 = 2 * err2;
		let e4 = 2 * err3;

		if (e2 > -dy) {
			err1 -= dy;
			err2 -= dz;
			x1 += sx;
		}
		if (e2 < dx) {
			err1 += dx;
			err3 -= dz;
			y1 += sy;
		}
		if (e3 > -dz) {
			err2 += dy;
			err3 += dx;
			z1 += sz;
		}
	}
}

