in the …/project/src/datacode.rs part:  use std::collections::{BTreeMap, HashMap, HashSet};
use std::cmp::Reverse;
use std::fs::File;
use std::io::{self, BufRead, BufReader};

#[derive(Debug)]
pub struct MyGlobalStruct<'a, T> {
    hashmap: HashMap<&'a str, (T, T, T)>,
    hashset: HashSet<String>,
    vec: Vec<(&'a str, (T, T, T))>,
    binary_heap: BinaryHeap<(T, &'a str, T)>,
    // add other fields as needed
}

#[derive(Debug)]
pub struct BinaryHeap<T> {
    heap: Vec<T>,
}

impl<T: Ord> BinaryHeap<T> {
    pub fn new() -> Self {
        BinaryHeap { heap: Vec::new() }
    }

    pub fn push(&mut self, x: T) {
        self.heap.push(x);
        self.heap.sort_by_key(|k| Reverse(k));
    }

    pub fn pop(&mut self) -> Option<T> {
        self.heap.pop()
    }
}

impl<'a, T> MyGlobalStruct<'a, T>
where
    T: Clone,
{
    pub fn new() -> MyGlobalStruct<'a, T> {
        MyGlobalStruct {
            hashmap: HashMap::new(),
            hashset: HashSet::new(),
            vec: Vec::new(),
            binary_heap: BinaryHeap::new(),
            // initialize other fields as needed
        }
    }

    pub fn from_files(file_paths: &[&str]) -> io::Result<MyGlobalStruct<'a, T>> {
        let mut data = MyGlobalStruct::new();

        for file_path in file_paths {
            let file = File::open(file_path)?;
            let reader = BufReader::new(file);

            for line in reader.lines() {
                if let Ok(data_row) = line {
                    let row = data_row.split('\t').collect::<Vec<&str>>();

                    if row.len() == 3 {
                        let (key, value1, value2) = (row[0], row[1], row[2]);
                        data
                            .hashmap
                            .insert(key, (value1.to_string(), value2.to_string(), "".to_string()));
                        data.hashset.insert(data_row);
                        data.vec.push((key, (value1.to_string(), value2.to_string(), "".to_string())));
                        data.binary_heap.push((value1.to_string(), key, value2.to_string()));
                    }
                }
            }
        }

        Ok(data)
    }

    // add other methods as needed
}

