int choice(bool (flip_func)(*int), void (fail_func)(*int), int* arr, int n) {
    if (n < 1) {
        fail_func(arr);
    } else if (flip_func(arr)) {
        return n;
    } else {
        return choice(flip_func, fail_func, arr, n - 1);
    }
}

